 1	import type { FC } from 'react';
 2	import { SelectableCard } from 'src/modules/Providers/utils/components/Gallery/SelectableCard';
 3	import { SelectableGallery } from 'src/modules/Providers/utils/components/Gallery/SelectableGallery';
 4	
 5	import { FormGroupWithHelpText } from '@components/common/FormGroupWithHelpText/FormGroupWithHelpText';
 6	import type { V1beta1Provider } from '@kubev2v/types';
 7	import { Flex, FlexItem, HelperText, HelperTextItem, Tooltip } from '@patternfly/react-core';
 8	import { getType } from '@utils/crds/common/selectors';
 9	import { useIsDarkTheme } from '@utils/hooks/useIsDarkTheme';
10	import { useForkliftTranslation } from '@utils/i18n';
11	
12	import { providerCardItems } from '../utils/providerCardItems';
13	
14	type ProviderCardsSelectProps = {
15	  newProvider: V1beta1Provider;
16	  handleProviderTypeChange: (type: string | null) => void;
17	};
18	
19	const ProviderCardsSelect: FC<ProviderCardsSelectProps> = ({
20	  handleProviderTypeChange,
21	  newProvider,
22	}) => {
23	  const { t } = useForkliftTranslation();
24	  const isDarkTheme = useIsDarkTheme();
25	  const providerItems = providerCardItems(isDarkTheme);
26	
27	  return (
28	    <FormGroupWithHelpText label={t('Provider type')} isRequired fieldId="ProviderType">
29	      {getType(newProvider) ? (
30	        <Flex>
31	          <FlexItem className="forklift--create-provider-edit-card-selected">
32	            <SelectableCard
33	              title={providerItems[getType(newProvider) ?? '']?.title}
34	              titleLogo={providerItems[getType(newProvider) ?? '']?.logo}
35	              onChange={() => {
36	                handleProviderTypeChange(null);
37	              }}
38	              isSelected
39	              isCompact
40	              content={
41	                <Tooltip
42	                  isVisible
43	                  content={<div>{t('Click to select a different provider from the list.')}</div>}
44	                >
45	                  <HelperText>
46	                    <HelperTextItem variant="indeterminate">
47	                      {t('Click to unselect.')}
48	                    </HelperTextItem>
49	                  </HelperText>
50	                </Tooltip>
51	              }
52	            />
53	          </FlexItem>
54	        </Flex>
55	      ) : (
56	        <SelectableGallery
57	          selectedID={getType(newProvider)}
58	          items={providerItems}
59	          onChange={handleProviderTypeChange}
60	        />
61	      )}
62	    </FormGroupWithHelpText>
63	  );
64	};
65	
66	export default ProviderCardsSelect;

